/* AI Shield local offline QR scanner shim. Provides a minimal Html5Qrcode-compatible API using the browser BarcodeDetector. */
(function(){
  "use strict";
  function makeError(message){
    var err = new Error(message);
    err.name = "Html5QrcodeLocalShimError";
    return err;
  }

  class Html5Qrcode {
    constructor(elementId){
      this.elementId = elementId;
      this.element = document.getElementById(elementId);
      this.stream = null;
      this.video = null;
      this.detector = null;
      this.running = false;
      this.loopTimer = null;
      this.lastDecodeAt = 0;
    }

    static getCameras(){
      if (!navigator.mediaDevices || !navigator.mediaDevices.enumerateDevices) {
        return Promise.resolve([]);
      }
      return navigator.mediaDevices.enumerateDevices()
        .then(function(devices){
          return devices
            .filter(function(device){ return device.kind === "videoinput"; })
            .map(function(device, index){
              return {
                id: device.deviceId,
                label: device.label || ("Camera " + (index + 1))
              };
            });
        });
    }

    async start(cameraConfig, config, qrCodeSuccessCallback, qrCodeErrorCallback){
      if (!this.element) throw makeError("QR scanner container not found: " + this.elementId);
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw makeError("此瀏覽器不支援相機存取。請改用 HTTPS 網址或直接貼上 QR Code 內容。 ");
      }
      if (!window.BarcodeDetector) {
        throw makeError("此瀏覽器不支援離線 QR 掃描核心 BarcodeDetector。請改用 Chrome/Android 測試，或直接貼上 QR Code 內容。 ");
      }

      var supportedFormats = [];
      if (typeof BarcodeDetector.getSupportedFormats === "function") {
        try { supportedFormats = await BarcodeDetector.getSupportedFormats(); } catch(e) { supportedFormats = []; }
      }
      if (supportedFormats.length && supportedFormats.indexOf("qr_code") === -1) {
        throw makeError("此瀏覽器的 BarcodeDetector 尚未支援 QR Code。請直接貼上 QR Code 內容。 ");
      }

      await this.stop().catch(function(){});
      this.detector = new BarcodeDetector({ formats: ["qr_code"] });

      var constraints = { video: {} };
      if (cameraConfig && cameraConfig.facingMode) {
        constraints.video.facingMode = cameraConfig.facingMode;
      } else if (cameraConfig && cameraConfig.deviceId) {
        constraints.video.deviceId = { exact: cameraConfig.deviceId };
      } else {
        constraints.video.facingMode = "environment";
      }

      this.stream = await navigator.mediaDevices.getUserMedia(constraints);
      this.video = document.createElement("video");
      this.video.setAttribute("playsinline", "true");
      this.video.setAttribute("muted", "true");
      this.video.autoplay = true;
      this.video.style.width = "100%";
      this.video.style.height = "100%";
      this.video.style.minHeight = "250px";
      this.video.style.objectFit = "cover";
      this.video.srcObject = this.stream;

      this.element.innerHTML = "";
      this.element.appendChild(this.video);

      await this.video.play();
      this.running = true;

      var fps = Math.max(1, Number(config && config.fps) || 10);
      var intervalMs = Math.max(100, Math.floor(1000 / fps));
      var self = this;

      async function scanOnce(){
        if (!self.running || !self.video || self.video.readyState < 2) return;
        try {
          var now = Date.now();
          if (now - self.lastDecodeAt < intervalMs) return;
          self.lastDecodeAt = now;
          var codes = await self.detector.detect(self.video);
          if (codes && codes.length) {
            var rawValue = codes[0].rawValue || codes[0].rawData || "";
            if (rawValue && typeof qrCodeSuccessCallback === "function") {
              qrCodeSuccessCallback(String(rawValue), { decodedText: String(rawValue), result: codes[0] });
            }
          }
        } catch (error) {
          if (typeof qrCodeErrorCallback === "function") qrCodeErrorCallback(error && error.message ? error.message : String(error));
        }
      }

      this.loopTimer = window.setInterval(scanOnce, intervalMs);
      return Promise.resolve();
    }

    async stop(){
      this.running = false;
      if (this.loopTimer) {
        window.clearInterval(this.loopTimer);
        this.loopTimer = null;
      }
      if (this.video) {
        try { this.video.pause(); } catch(e) {}
        try { this.video.srcObject = null; } catch(e) {}
      }
      if (this.stream) {
        try { this.stream.getTracks().forEach(function(track){ track.stop(); }); } catch(e) {}
      }
      this.stream = null;
      this.video = null;
      if (this.element) this.element.innerHTML = "";
      return Promise.resolve();
    }

    clear(){
      if (this.element) this.element.innerHTML = "";
    }
  }

  window.Html5Qrcode = Html5Qrcode;
})();
